workflows.preview:
name: Curator

on:
  issue_comment:
    types: [created]

permissions:
  contents: write
  issues: write
  actions: read

jobs:
  gateway-diagnostic:
    name: Curator Gateway Diagnostic
    if: |
      github.event.issue.number == 31 &&
      github.actor != 'github-actions[bot]' &&
      github.event.comment.user.type != 'Bot' &&
      contains(github.event.comment.body, '@curator')
    runs-on: ubuntu-latest
    timeout-minutes: 5

    steps:
      - name: Post gateway diagnostic report
        uses: actions/github-script@v7
        with:
          github-token: ${{ secrets.AI_SYSTEM_GITHUB_PAT }}
          script: |
            let runnerLines = [];
            let runnerSummary = 'unknown';
            try {
              const runners = await github.rest.actions.listSelfHostedRunnersForRepo({
                owner: context.repo.owner,
                repo: context.repo.repo,
                per_page: 100
              });
              const list = runners.data.runners || [];
              runnerSummary = `${list.length} self-hosted runner(s) visible`;
              if (list.length === 0) {
                runnerLines.push('| self-hosted runners | ❌ | none visible to AI_SYSTEM_GITHUB_PAT |');
              } else {
                for (const r of list) {
                  const labels = (r.labels || []).map(l => l.name).join(', ');
                  const status = r.status === 'online' ? '✅ online' : `❌ ${r.status}`;
                  runnerLines.push(`| runner:${r.name} | ${status} | labels: ${labels}; busy: ${r.busy} |`);
                }
              }

